/*
 * Curl_h3_priority_parse() parses an RFC 9218 Extensible Priority string of
 * the form "u=N[,i]" where N is urgency 0 (highest) to 7 (lowest) and the
 * optional ",i" token enables incremental delivery.
 */
CURLcode Curl_h3_priority_parse(const char *priority,
                                int *urgency, bool *incremental)
{
  const char *p = priority;
  int u;

  if(!p || *p == '\0')
    return CURLE_BAD_FUNCTION_ARGUMENT;

  if(p[0] != 'u' || p[1] != '=')
    return CURLE_BAD_FUNCTION_ARGUMENT;
  p += 2;

  if(*p < '0' || *p > '9')
    return CURLE_BAD_FUNCTION_ARGUMENT;
  u = *p - '0';
  p++;

  if(u > 7)
    return CURLE_BAD_FUNCTION_ARGUMENT;

  *urgency = u;
  *incremental = FALSE;

  if(*p == '\0')
    return CURLE_OK;

  if(*p != ',' || p[1] != 'i' || p[2] != '\0')
    return CURLE_BAD_FUNCTION_ARGUMENT;

  *incremental = TRUE;
  return CURLE_OK;
}

