/* Unit tests for Curl_h3_priority_parse() (RFC 9218 Extensible Priorities) */

#include "curlcheck.h"
#include "setopt.h"

static CURLcode unit_setup(void)
{
  return CURLE_OK;
}

static void unit_stop(void)
{
}

UNITTEST_START
{
  CURLcode rc;
  int urgency;
  bool incremental;

  /* "u=3" → urgency 3, not incremental */
  urgency = -1;
  incremental = TRUE;
  rc = Curl_h3_priority_parse("u=3", &urgency, &incremental);
  fail_unless(rc == CURLE_OK, "u=3 should succeed");
  fail_unless(urgency == 3, "u=3 urgency should be 3");
  fail_unless(incremental == FALSE, "u=3 incremental should be FALSE");

  /* "u=0,i" → urgency 0, incremental */
  urgency = -1;
  incremental = FALSE;
  rc = Curl_h3_priority_parse("u=0,i", &urgency, &incremental);
  fail_unless(rc == CURLE_OK, "u=0,i should succeed");
  fail_unless(urgency == 0, "u=0,i urgency should be 0");
  fail_unless(incremental == TRUE, "u=0,i incremental should be TRUE");

  /* "u=7" → urgency 7 (lowest), not incremental */
  urgency = -1;
  incremental = TRUE;
  rc = Curl_h3_priority_parse("u=7", &urgency, &incremental);
  fail_unless(rc == CURLE_OK, "u=7 should succeed");
  fail_unless(urgency == 7, "u=7 urgency should be 7");
  fail_unless(incremental == FALSE, "u=7 incremental should be FALSE");

  /* "u=3,i" → urgency 3, incremental */
  urgency = -1;
  incremental = FALSE;
  rc = Curl_h3_priority_parse("u=3,i", &urgency, &incremental);
  fail_unless(rc == CURLE_OK, "u=3,i should succeed");
  fail_unless(urgency == 3, "u=3,i urgency should be 3");
  fail_unless(incremental == TRUE, "u=3,i incremental should be TRUE");

  /* "u=8" → urgency out of range, must fail */
  rc = Curl_h3_priority_parse("u=8", &urgency, &incremental);
  fail_unless(rc == CURLE_BAD_FUNCTION_ARGUMENT, "u=8 should fail (out of range)");

  /* "" → empty string, must fail */
  rc = Curl_h3_priority_parse("", &urgency, &incremental);
  fail_unless(rc == CURLE_BAD_FUNCTION_ARGUMENT, "empty string should fail");

  /* NULL → must fail */
  rc = Curl_h3_priority_parse(NULL, &urgency, &incremental);
  fail_unless(rc == CURLE_BAD_FUNCTION_ARGUMENT, "NULL should fail");

  /* "u=3,x" → unknown token after urgency, must fail */
  rc = Curl_h3_priority_parse("u=3,x", &urgency, &incremental);
  fail_unless(rc == CURLE_BAD_FUNCTION_ARGUMENT, "u=3,x should fail (bad token)");

  /* "priority=3" → wrong format, must fail */
  rc = Curl_h3_priority_parse("priority=3", &urgency, &incremental);
  fail_unless(rc == CURLE_BAD_FUNCTION_ARGUMENT, "priority=3 should fail (wrong format)");

  /* "u=3,i,extra" → trailing garbage, must fail */
  rc = Curl_h3_priority_parse("u=3,i,extra", &urgency, &incremental);
  fail_unless(rc == CURLE_BAD_FUNCTION_ARGUMENT, "u=3,i,extra should fail (trailing garbage)");
}
